"use client";

import * as React from "react";
import Image from "next/image";
import {
  type MotionValue,
  useMotionValueEvent,
} from "motion/react";

import { cn } from "@/lib/utils";
import {
  useMediaQuery,
  usePrefersReducedMotion,
} from "@/components/experience/experience-runtime";
import { useElementScrollProgress } from "@/components/experience/use-element-scroll-progress";

export type ImageSequenceScrubProps = Omit<React.ComponentProps<"section">, "children"> & {
  alt: string;
  frames: string[];
  label: string;
  mobileFrames?: string[];
  objectFit?: "cover" | "contain";
  overlay?: React.ReactNode;
  poster: string;
  preloadRadius?: number;
  progress?: MotionValue<number>;
  scrollScreens?: number;
  stageClassName?: string;
};

function drawFrame(
  canvas: HTMLCanvasElement,
  image: HTMLImageElement,
  objectFit: "cover" | "contain",
) {
  const rect = canvas.getBoundingClientRect();
  if (!rect.width || !rect.height || !image.naturalWidth || !image.naturalHeight) return;

  const ratio = Math.min(window.devicePixelRatio || 1, 2);
  const width = Math.round(rect.width * ratio);
  const height = Math.round(rect.height * ratio);
  if (canvas.width !== width || canvas.height !== height) {
    canvas.width = width;
    canvas.height = height;
  }

  const context = canvas.getContext("2d", { alpha: false });
  if (!context) return;
  const scale = objectFit === "cover"
    ? Math.max(width / image.naturalWidth, height / image.naturalHeight)
    : Math.min(width / image.naturalWidth, height / image.naturalHeight);
  const drawWidth = image.naturalWidth * scale;
  const drawHeight = image.naturalHeight * scale;
  context.clearRect(0, 0, width, height);
  context.drawImage(image, (width - drawWidth) / 2, (height - drawHeight) / 2, drawWidth, drawHeight);
}

/** Native vertical scroll scrubs an optimized still-image sequence on one canvas. */
export function ImageSequenceScrub({
  alt,
  className,
  frames,
  label,
  mobileFrames,
  objectFit = "cover",
  overlay,
  poster,
  preloadRadius = 6,
  progress: controlledProgress,
  scrollScreens = 4,
  stageClassName,
  style,
  ...props
}: ImageSequenceScrubProps) {
  const rootRef = React.useRef<HTMLElement>(null);
  const canvasRef = React.useRef<HTMLCanvasElement>(null);
  const imagesRef = React.useRef(new Map<number, HTMLImageElement>());
  const frameRef = React.useRef(0);
  const reducedMotion = usePrefersReducedMotion();
  const mobile = useMediaQuery("(max-width: 767.98px)");
  const sources = mobile && mobileFrames?.length ? mobileFrames : frames;
  const scrollYProgress = useElementScrollProgress(rootRef);
  const progress = controlledProgress ?? scrollYProgress;

  const loadFrame = React.useCallback((index: number) => {
    const src = sources[index];
    if (!src || imagesRef.current.has(index)) return;
    const image = new window.Image();
    image.decoding = "async";
    image.src = src;
    imagesRef.current.set(index, image);
    image.addEventListener("load", () => {
      if (frameRef.current === index && canvasRef.current) {
        drawFrame(canvasRef.current, image, objectFit);
      }
    }, { once: true });
  }, [objectFit, sources]);

  const renderIndex = React.useCallback((index: number) => {
    if (sources.length === 0) return;
    const safeIndex = Math.max(0, Math.min(sources.length - 1, index));
    frameRef.current = safeIndex;
    const start = Math.max(0, safeIndex - preloadRadius);
    const end = Math.min(sources.length - 1, safeIndex + preloadRadius);
    for (let frame = start; frame <= end; frame += 1) loadFrame(frame);
    // Evict decoded frames far outside the preload window (keeping the first and
    // last frame) so long sequences do not retain every frame forever.
    const evictionDistance = preloadRadius * 3;
    for (const cachedIndex of imagesRef.current.keys()) {
      if (cachedIndex === 0 || cachedIndex === sources.length - 1) continue;
      if (Math.abs(cachedIndex - safeIndex) > evictionDistance) {
        imagesRef.current.delete(cachedIndex);
      }
    }
    const image = imagesRef.current.get(safeIndex);
    if (image?.complete && canvasRef.current) drawFrame(canvasRef.current, image, objectFit);
  }, [loadFrame, objectFit, preloadRadius, sources.length]);

  React.useEffect(() => {
    imagesRef.current.clear();
    renderIndex(0);
  }, [renderIndex, sources]);

  React.useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const observer = new ResizeObserver(() => renderIndex(frameRef.current));
    observer.observe(canvas);
    return () => observer.disconnect();
  }, [renderIndex]);

  useMotionValueEvent(progress, "change", (value) => {
    renderIndex(Math.round(value * Math.max(0, sources.length - 1)));
  });

  if (reducedMotion || sources.length < 2) {
    return (
      <section ref={rootRef} aria-label={label} className={cn("relative isolate min-h-svh", className)} style={style} {...props}>
        <Image alt={alt} src={poster} fill sizes="100vw" className={cn("-z-10", objectFit === "cover" ? "object-cover" : "object-contain")} />
        {overlay}
      </section>
    );
  }

  return (
    <section
      ref={rootRef}
      aria-label={label}
      data-image-sequence
      className={cn("relative isolate", className)}
      style={{ minHeight: `${Math.max(2, scrollScreens) * 100}svh`, ...style }}
      {...props}
    >
      <div className={cn("sticky top-0 h-svh overflow-hidden", stageClassName)}>
        <Image alt={alt} src={poster} fill priority sizes="100vw" className={cn("-z-10", objectFit === "cover" ? "object-cover" : "object-contain")} />
        <canvas ref={canvasRef} aria-hidden className="absolute inset-0 size-full" />
        {overlay ? <div className="absolute inset-0 z-10">{overlay}</div> : null}
      </div>
    </section>
  );
}

"use client";

import * as React from "react";
import { useMotionValue } from "motion/react";

/**
 * Stable `start start` → `end end` progress for pinned sections. It measures
 * the section itself, so progress remains monotonic all the way to the final
 * pixel and does not wrap when a sticky child releases.
 */
export function useElementScrollProgress(
  target: React.RefObject<HTMLElement | null>,
) {
  const progress = useMotionValue(0);

  React.useEffect(() => {
    const element = target.current;
    if (!element) return;
    let frame = 0;
    const measure = () => {
      const rect = element.getBoundingClientRect();
      const travel = Math.max(1, element.offsetHeight - window.innerHeight);
      progress.set(Math.max(0, Math.min(1, -rect.top / travel)));
    };
    const update = () => {
      cancelAnimationFrame(frame);
      frame = requestAnimationFrame(measure);
    };
    const resizeObserver = new ResizeObserver(update);
    resizeObserver.observe(element);
    window.addEventListener("scroll", update, { passive: true });
    window.addEventListener("resize", update, { passive: true });
    // Synchronous first measurement: consumers that render a bootstrap frame
    // before the first animation frame (e.g. a restored scroll position in a
    // background tab) already see the true progress.
    measure();
    return () => {
      cancelAnimationFrame(frame);
      resizeObserver.disconnect();
      window.removeEventListener("scroll", update);
      window.removeEventListener("resize", update);
    };
  }, [progress, target]);

  return progress;
}

"use client";

import * as React from "react";

const subscribeToHydration = () => () => undefined;

export function useHydrated() {
  return React.useSyncExternalStore(subscribeToHydration, () => true, () => false);
}

export function useMediaQuery(query: string, serverValue = false) {
  const subscribe = React.useCallback(
    (onChange: () => void) => {
      const media = window.matchMedia(query);
      media.addEventListener("change", onChange);
      return () => media.removeEventListener("change", onChange);
    },
    [query],
  );
  const getSnapshot = React.useCallback(() => window.matchMedia(query).matches, [query]);
  return React.useSyncExternalStore(subscribe, getSnapshot, () => serverValue);
}

/**
 * Hydration-safe reduced-motion preference: false on the server and during
 * hydration, then live. Replaces the repeated `mounted && useReducedMotion()`
 * pattern.
 */
export function usePrefersReducedMotion() {
  return useMediaQuery("(prefers-reduced-motion: reduce)");
}

/** True on touch-first devices; use to swap pointer effects for static or rail modes. */
export function useCoarsePointer() {
  return useMediaQuery("(pointer: coarse)");
}

/** True only when a hover-capable precise pointer is present. */
export function useFinePointer() {
  return useMediaQuery("(hover: hover) and (pointer: fine)");
}

export function clamp01(value: number) {
  return Math.min(1, Math.max(0, value));
}

export function mix(from: number, to: number, amount: number) {
  return from + (to - from) * amount;
}

export function damp(current: number, target: number, smoothing: number, deltaSeconds: number) {
  return mix(current, target, 1 - Math.exp(-Math.max(0.01, smoothing) * deltaSeconds));
}

/** Returns the frames sorted by `at`, reusing the input when it is already ordered. */
export function sortKeyframes<T extends { at: number }>(frames: T[]): T[] {
  for (let index = 1; index < frames.length; index += 1) {
    if (frames[index - 1]!.at > frames[index]!.at) {
      return [...frames].sort((left, right) => left.at - right.at);
    }
  }
  return frames;
}

export function resolveKeyframes<T extends { at: number }>(
  frames: T[],
  progress: number,
): { from: T; to: T; mix: number } {
  if (frames.length === 0) throw new Error("Experience keyframes cannot be empty.");
  const sorted = sortKeyframes(frames);
  if (progress <= sorted[0]!.at) return { from: sorted[0]!, to: sorted[0]!, mix: 0 };
  for (let index = 0; index < sorted.length - 1; index += 1) {
    const from = sorted[index]!;
    const to = sorted[index + 1]!;
    if (progress <= to.at) {
      const span = Math.max(0.0001, to.at - from.at);
      return { from, to, mix: clamp01((progress - from.at) / span) };
    }
  }
  const final = sorted.at(-1)!;
  return { from: final, to: final, mix: 0 };
}

export function supportsWebGL() {
  try {
    const canvas = document.createElement("canvas");
    return Boolean(
      canvas.getContext("webgl2", { failIfMajorPerformanceCaveat: true })
      || canvas.getContext("webgl", { failIfMajorPerformanceCaveat: true }),
    );
  } catch {
    return false;
  }
}
